func newWorkflowArchiveCmd(flags *rootFlags) *cobra.Command {
	var dbPath string
	var full bool

	cmd := &cobra.Command{
		Use:   "archive",
		Short: "Sync all resources to local store for offline access and search",
		Long: `Archive fetches all syncable resources from the API and stores them in a
local SQLite database. Supports incremental sync (only new data since last run)
and full resync. After archiving, use 'search' for instant full-text search.`,
		Example: `  # Archive all resources
  openfda-pp-cli workflow archive

  # Full re-archive (ignore previous sync state)
  openfda-pp-cli workflow archive --full`,
		RunE: func(cmd *cobra.Command, args []string) error {
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			c.NoCache = true

			if dbPath == "" {
				dbPath = defaultDBPath("openfda-pp-cli")
			}
			s, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening store: %w", err)
			}
			defer s.Close()

			resources := []string{"animal-events", "device-510k", "device-classification", "device-covid19", "device-events", "device-pma", "device-recall-detail", "device-recalls", "device-registration", "device-udi", "drug-approvals", "drug-events", "drug-labels", "drug-ndc", "drug-recalls", "drug-shortages", "food-events", "food-recalls", "nsde", "substance", "tobacco-problems"}
			totalSynced := 0

			for _, resource := range resources {
				cursor := ""
				if !full {
					existing, _, _, err := s.GetSyncState(resource)
					if err == nil && existing != "" {
						cursor = existing
					}
				}

				fmt.Fprintf(cmd.ErrOrStderr(), "Syncing %s...\n", resource)

				// OpenFDA uses offset-based pagination (skip), not cursor-based.
				skip := 0
				params := map[string]string{"limit": "100"}

				count := 0
				for {
					apiPath, pathErr := syncResourcePath(resource)
					if pathErr != nil {
						fmt.Fprintf(cmd.ErrOrStderr(), "  warning: %s: %v\n", resource, pathErr)
						break
					}
					if skip > 0 {
						params["skip"] = fmt.Sprintf("%d", skip)
					}
					data, fetchErr := c.Get(apiPath, params)
					if fetchErr != nil {
						fmt.Fprintf(cmd.ErrOrStderr(), "  warning: %s: %v\n", resource, fetchErr)
						break
					}
					// Try to extract "results" array from OpenFDA's
					// {"meta": {...}, "results": [...]} envelope.
					var items []json.RawMessage
					var envelope struct {
						Results json.RawMessage `json:"results"`
					}
					if err := json.Unmarshal(data, &envelope); err == nil && len(envelope.Results) > 0 {
						json.Unmarshal(envelope.Results, &items)
					}
					if len(items) == 0 {
						// Fallback: try parsing as a bare array or single object.
						if err := json.Unmarshal(data, &items); err != nil || len(items) == 0 {
							if err := s.Upsert(resource, resource+"-singleton", data); err != nil {
								fmt.Fprintf(cmd.ErrOrStderr(), "  warning: store %s: %v\n", resource, err)
							}
							count++
							break
						}
					}
					if len(items) == 0 {
						break
					}
					for _, item := range items {
						var obj struct {
							ID string `json:"id"`
						}
						json.Unmarshal(item, &obj)
						id := obj.ID
						if id == "" {
							id = fmt.Sprintf("%s-%d", resource, count)
						}
						if err := s.Upsert(resource, id, item); err != nil {
							fmt.Fprintf(cmd.ErrOrStderr(), "  warning: store %s/%s: %v\n", resource, id, err)
						}
						cursor = id
						count++
					}
					if len(items) < 100 {
						break
					}
					skip += len(items)
				}

				if count > 0 {
					s.SaveSyncState(resource, cursor, count)
				}
				totalSynced += count
				fmt.Fprintf(cmd.ErrOrStderr(), "  %s: %d items\n", resource, count)
			}

			if flags.asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]any{
					"resources_synced": len(resources),
					"total_items":      totalSynced,
					"store_path":       dbPath,
					"timestamp":        time.Now().UTC().Format(time.RFC3339),
				})
			}

			fmt.Fprintf(cmd.OutOrStdout(), "Archived %d items across %d resources to %s\n", totalSynced, len(resources), dbPath)
			return nil
		},
	}

	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: ~/.local/share/openfda-pp-cli/data.db)")
	cmd.Flags().BoolVar(&full, "full", false, "Full re-archive (ignore previous sync state)")

	return cmd
}

func newWorkflowStatusCmd(flags *rootFlags) *cobra.Command {
	var dbPath string

	cmd := &cobra.Command{
		Use:         "status",
		Short:       "Show local archive status and sync state for all resources",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Example: `  # Show archive status
  openfda-pp-cli workflow status

  # Show status as JSON
  openfda-pp-cli workflow status --json`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if dbPath == "" {
				dbPath = defaultDBPath("openfda-pp-cli")
			}
			s, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening store: %w", err)
			}
			defer s.Close()

			status, err := s.Status()
			if err != nil {
				return err
			}

			if flags.asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(status)
			}

			if len(status) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "No archived data. Run 'workflow archive' to sync.")
				return nil
			}

			fmt.Fprintln(cmd.OutOrStdout(), "Archive Status:")
			total := 0
			for resource, count := range status {
				fmt.Fprintf(cmd.OutOrStdout(), "  %-30s %d items\n", resource, count)
				total += count
			}
			fmt.Fprintf(cmd.OutOrStdout(), "\n  Total: %d items\n", total)
			fmt.Fprintf(cmd.OutOrStdout(), "  Store: %s\n", dbPath)
			return nil
		},
	}

	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")

	return cmd
}

